// ----------------------- basic methods of sdk --------------------------
async function call(data) {
    const callResult = await cfx.call(data)
    console.log(`callResult ${JSON.stringify(callResult)}`)
    return callResult;
}

async function getStatus() {
    const status = await cfx.getStatus()
    console.log(`status ${JSON.stringify(status)}`)
    return status;
}

async function getAccount(addr) {
    const account = await cfx.getAccount(addr)
    console.log(`addr ${addr} account ${JSON.stringify(account)} `)
    return account;
}

async function getNextNonce(addr) {
    const nonce = await cfx.getNextNonce(addr)
    console.log(`nonce ${JSON.stringify(nonce)}`)
    return nonce;
}

async function getTransactionByHash(txHash) {
    console.log(`getTransactionByHash txHash ${txHash}`)
    const tx = await cfx.getTransactionByHash(txHash);
    console.log(`tx ${JSON.stringify(tx)}`);
}

async function getTransactionReceipt(txHash) {
    console.log(`getTransactionReceipt txHash ${txHash}`)
    const receipt = await cfx.getTransactionReceipt(txHash);
    console.log(`receipt ${JSON.stringify(receipt)}`);
}

async function getEpochReceipts(epoch) {
    console.log(`getEpochReceipt epoch ${epoch}`)
    const epochReceipts = await cfx.getEpochReceipts(epoch);
    console.log(`epochReceipts ${JSON.stringify(epochReceipts)}`);
}

async function getToken(addr) {
    const tokenInfo = await tokenTool.getToken(addr);
    console.log(`tokenInfo ${JSON.stringify(tokenInfo)}`)
}

