async function sendRawTransaction(data, to = null) {
    const account = await cfx.getAccount(fromAddress);
    console.log(`balance of fromAddress------${account.balance}`);
    // raw
    const nonce = await cfx.getNextNonce(fromAddress);
    console.log(`nonce------${JSON.stringify(nonce)}`);
    const estimate = {gasLimit: 50000000, storageCollateralized: 1024}; // await cfx.estimateGasAndCollateral({ from: fromAddress, to: null, nonce, data }); not implemented in consortium
    console.log(`estimateGas------${JSON.stringify(estimate)}`);
    const epochNumber = await cfx.getEpochNumber();
    console.log(`proposedEpoch------${JSON.stringify(epochNumber)}`);
    const gasPrice = BigInt(10000000000); // await cfx.getGasPrice(); not implemented in consortium
    console.log(`estimateGasPrice------${JSON.stringify(gasPrice)}`);
    const rawTransaction = {
        nonce,
        gasPrice,
        gas: estimate.gasLimit,
        to,
        value : 0,
        storageLimit: estimate.storageCollateralized, // unused in consortium
        epochHeight: epochNumber,
        chainId: 0,
        data,
    };
    const tx = new ConsortiumTransaction(rawTransaction);
    console.log(`------tx:\n${JSON.stringify(tx)}}\n------`)

    // sign
    tx.sign(fromAddressPrivateKey, networkId);
    console.log(`------txSigned:\n${JSON.stringify(tx)}\n------`)

    // hex
    const serializedTx = tx.serialize();
    console.log(`------txSerialized:\n${JSON.stringify(serializedTx)}\n------`)

    // call or send
    let receipt
    if(debug) {
        // call
        receipt = await cfx.call({ from: fromAddress, to, gasPrice, gas: estimate.gasLimit, value : 0, data, nonce });
    } else{
        // send
        receipt = await cfx.sendRawTransaction(serializedTx).executed();
    }

    console.log(`------receipt:\n${JSON.stringify(receipt)}\n------`)
    return receipt;
}

// ------------------- deploy contracts used by scan ---------------------
async function deployAnnouncement() {
    const data = '';
    const {transactionHash: txHash, contractCreated} = await sendRawTransaction(data);
    console.log(`contract announcement ${contractCreated} deployed at tx ${txHash} `);

}

async function deployScanUtil() {
    const data = '';
    const {transactionHash: txHash, contractCreated} = await sendRawTransaction(data);
    console.log(`contract scan-util ${contractCreated} deployed at tx ${txHash} `);
}

