// --------------------------- mint erc 20 ------------------------------
const addrERC20 = 'cfx:accrn9ahnwchru0xkt0f8aaw0z9tnm8knpb3eusmgb';

async function mint20(owner, amount) {
    const ownerAddr = format.hexAddress(owner);

    // raw data
    const signature = keccak256(toUtf8Bytes("addTokens(address,uint256)"));
    const abiCoder = new ethers.utils.AbiCoder();
    const result = abiCoder.encode(["address", "uint256"], [ownerAddr, amount]);
    const data = ethers.utils.hexConcat([ethers.utils.hexDataSlice(signature, 0, 4), result]);
    console.log(`data`, data);

    // send tx
    const receipt = await sendRawTransaction(data, addrERC20);
    console.log(`ERC20 ${tokenId} minted at tx ${receipt?.transactionHash}`, receipt);

    return receipt;
}

// --------------------------- mint nft 721 ------------------------------
const addrNFT721 = 'cfx:acfs01nrhvbp8jbz1duzh4t72vyrjxps46wf840map';

async function mint721(owner, tokenId, tokenUri) {
    const ownerAddr = format.hexAddress(owner);

    // raw data
    const signature = keccak256(toUtf8Bytes("mint(address,uint256,string)"));
    const abiCoder = new ethers.utils.AbiCoder();
    const result = abiCoder.encode(["address", "uint256", "string"], [ownerAddr, tokenId, tokenUri]);
    const data = ethers.utils.hexConcat([ethers.utils.hexDataSlice(signature, 0, 4), result]);
    console.log(`data`, data);

    // send tx
    const receipt = await sendRawTransaction(data, addrNFT721);
    console.log(`NFT721 ${tokenId} minted at tx ${receipt?.transactionHash}`, receipt);

    return receipt;
}

// --------------------------- mint nft 1155 ------------------------------
const addrNFT1155 = 'cfx:acefh04830t8vzh9cxk3js1z6dfj1adz725r2dcka8';

async function mint1155(owner, tokenId, amount) {
    const ownerAddr = format.hexAddress(owner);

    // raw data
    const signature = keccak256(toUtf8Bytes("mint(address,uint256,uint256,bytes)"));
    const abiCoder = new ethers.utils.AbiCoder();
    const result = abiCoder.encode(["address", "uint256", "uint256", "bytes"], [ownerAddr, tokenId, amount, []]);
    const data = ethers.utils.hexConcat([ethers.utils.hexDataSlice(signature, 0, 4), result]);
    console.log(`data`, data);

    // send tx
    const receipt = await sendRawTransaction(data, addrNFT1155);
    console.log(`NFT1155 ${tokenId} minted at tx ${receipt?.transactionHash}`, receipt);

    return receipt;
}

// ------------------------ entry point method ---------------------------
async function init() {
    cfx = await initCfxSdk({
        url,
        networkId,
        defaultGasPrice: 1_000_000_000,
        consortiumMode: true,
        // logger: console,
    });
    tokenTool = new TokenTool(cfx);

    if(type === 10 || type === 721 || type === 1155) {
        const account = cfx.wallet.addPrivateKey(fromAddressPrivateKey);
        fromAddress = format.hexAddress(account.toString());
        const fromAddressBalance = await cfx.getBalance(account.toString());
        console.log(`account ${account} with hex ${format.hexAddress(account.toString())} has balance ${formatEther(fromAddressBalance)}`);
    }
}

async function run() {
    await init();
    if(type === 0) {
        await call();
    }
    if(type === 1) {
        await getStatus();
    }
    if(type === 2) {
        await getAccount(addr);
    }
    if(type === 3) {
        await getNextNonce(addr);
    }
    if(type === 4) {
        await getTransactionByHash(txHash);
    }
    if(type === 5) {
        await getTransactionReceipt(txHash);
    }
    if(type === 6) {
        await getEpochReceipts(epochNumber);
    }
    if(type === 7) {
        await getToken(addr);
    }

    if(type === 10) {
        await deploy();
    }
    if(type === 20) {
        await mint20(owner, amount);
    }
    if(type === 721) {
        await mint721(owner, tokenId, tokenUri);
    }
    if(type === 1155) {
        await mint1155(owner, tokenId, amount);
    }
}

async function main() {
    const args = process.argv.slice(2);
    url = args[0];
    networkId = Number(args[1]);
    type = Number(args[2]);
    console.log(`url ${url} networkId ${networkId} type ${type}`)

    // node common/contract/consortium-deploy.js url networkId typ addr
    if(type === 2 || type === 3 || type === 7) {
        addr = args[3];
        console.log(`type ${type} addr ${addr}`)
    }
    // node common/contract/consortium-deploy.js url networkId typ txHash
    if(type === 4 || type === 5) {
        txHash = args[3];
        console.log(`type ${type} txHash ${txHash}`)
    }
    // node common/contract/consortium-deploy.js url networkId typ epochNumber
    if(type === 6) {
        epochNumber = Number(args[3]);
        console.log(`type ${type} epochNumber ${epochNumber}`)
    }
    // node common/contract/consortium-deploy.js url networkId typ pk debug(O)
    if(type === 10) {
        fromAddressPrivateKey = args[3];
        (args?.length === 5) && (debug = args[4]);
        console.log(`type ${type} debug ${debug}`)
    }
    // node common/contract/consortium-deploy.js url networkId typ pk owner amount
    if(type === 20) {
        fromAddressPrivateKey = args[3];
        owner = args[4]; //'cfx:achew68x34cwu04aezbunyaz67gppakvmyn79tau56'
        amount = Number(args[5]);
        console.log(`owner`, owner, `amount`, amount);
    }
    // node common/contract/consortium-deploy.js url networkId typ pk owner tokenId tokenUri
    if(type === 721) {
        fromAddressPrivateKey = args[3];
        owner = args[4]; //'cfx:achew68x34cwu04aezbunyaz67gppakvmyn79tau56'
        tokenId = Number(args[5]);
        tokenUri = args[6];
        console.log(`owner`, owner, `tokenId`, tokenId, `tokenUri`, tokenUri);
    }
    // node common/contract/consortium-deploy.js url networkId typ pk owner tokenId tokenUri
    if(type === 1155) {
        fromAddressPrivateKey = args[3];
        owner = args[4]; //'cfx:achew68x34cwu04aezbunyaz67gppakvmyn79tau56'
        tokenId = Number(args[5]);
        amount = Number(args[6]);
        console.log(`owner`, owner, `tokenId`, tokenId, `amount`, amount);
    }

    run().then();
}

main().then();
